import React from 'react';

function Projects({ data }) {
  if (!data || data.length === 0) return null;

  return (
    <section id="projects" className="py-20 bg-white">
      <div className="max-w-7xl mx-auto px-4">
        <h2 className="text-4xl font-bold text-gray-800 mb-12 text-center">My Projects</h2>
        
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {data.map((project, index) => (
            <div 
              key={project.id} 
              className="group cursor-pointer transform transition hover:scale-105"
            >
              {/* Project Image Container */}
              <div className="relative overflow-hidden rounded-lg bg-gray-200 h-60 md:h-72 mb-4">
                <div className="w-full h-full bg-gradient-to-br from-blue-400 to-blue-600 flex items-center justify-center">
                  {project.icon ? (
                    <span className="text-6xl">{project.icon}</span>
                  ) : (
                    <span className="text-gray-400 text-center px-4">
                      {project.title}
                    </span>
                  )}
                </div>
                
                {project.image && (
                  <img 
                    src={project.image} 
                    alt={project.title}
                    className="absolute inset-0 w-full h-full object-cover group-hover:scale-110 transition duration-300"
                  />
                )}
              </div>
              
              {/* Project Info */}
              <div>
                <h3 className="text-xl font-bold text-gray-900 mb-1 group-hover:text-blue-600 transition">
                  {project.title}
                </h3>
                <p className="text-gray-600 text-sm mb-3">
                  {project.company}
                </p>
                {project.description && (
                  <p className="text-gray-600 text-sm leading-relaxed mb-4">
                    {project.description}
                  </p>
                )}
                
                {/* Tech Stack */}
                {project.tags && project.tags.length > 0 && (
                  <div className="flex flex-wrap gap-2">
                    {project.tags.map((tag, idx) => (
                      <span 
                        key={idx}
                        className="inline-block bg-blue-100 text-blue-600 px-3 py-1 rounded-full text-xs font-semibold"
                      >
                        {tag}
                      </span>
                    ))}
                  </div>
                )}
                
                {/* View Project Link */}
                {project.link && (
                  <a 
                    href={project.link}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="inline-block mt-4 text-blue-600 font-semibold hover:text-blue-700 transition"
                  >
                    View Project →
                  </a>
                )}
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Projects;
